);

CREATE TABLE games (
    id integer, -- example: [1, 2]
    games_year integer, -- example: [1992, 2012]
    games_name text, -- example: ['1992 Summer', '2012 Summer']
    season text, -- example: ['Summer', 'Winter']
    PRIMARY KEY (id)
);

CREATE TABLE games_city (
    games_id integer, -- example: [1, 2]
    city_id integer, -- example: [1, 2]
    CONSTRAINT fk_games_city_games_id FOREIGN KEY (games_id) REFERENCES games (id),
    CONSTRAINT fk_games_city_city_id FOREIGN KEY (city_id) REFERENCES city (id)
);

CREATE TABLE medal (
    id integer, -- example: [1, 2]
    medal_name text, -- example: ['Gold', 'Silver']
    PRIMARY KEY (id)
);

CREATE TABLE noc_region (
