    noc text, -- example: ['AFG', 'AHO']
    region_name text, -- example: ['Afghanistan', 'Netherlands Antilles']
    PRIMARY KEY (id)
);

CREATE TABLE person (
    id integer, -- example: [1, 2]
    full_name text, -- example: ['A Dijiang', 'A Lamusi']
    gender text, -- example: ['M', 'F']
    height integer, -- example: [180, 170]
    weight integer, -- example: [80, 60]
